    	if len(err) == 0 {
    		return ""
    	}

    	var b strings.Builder
    	for i := range len(err) {
    		if err[i] != nil {
    			if b.Len() > 0 {
    				b.WriteString("\n")
    			}
    			b.WriteString("[" + strconv.Itoa(i) + "]: " + err[i].Error())
    		}
    	}
    	return b.String()
    }
